	require.True(t, ok, "audit_data field should be present")

	// Unmarshal the audit data
	var evaluation AuditEvaluation
	err = json.Unmarshal([]byte(auditData.(string)), &evaluation)
	require.NoError(t, err)
	require.Equal(t, "policy:200", evaluation.PolicyKey)
	require.Equal(t, "evaluation-complete", evaluation.Result)
}

func TestPolicyAuditLoggerSetLogLevel(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel, false)

	require.Equal(t, logrus.InfoLevel, pal.logLevel)

	pal.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, pal.logLevel)
}

func TestPolicyAuditLoggerSetLogger(t *testing.T) {
	logger1 := logrus.New()
	logger2 := logrus.New()

	pal := NewPolicyAuditLogger(logger1, logrus.InfoLevel, false)
	require.Equal(t, logger1, pal.logger)

	pal.SetLogger(logger2)
	require.Equal(t, logger2, pal.logger)
}

func TestPolicyAuditLoggerSetEnableJSON(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel, false)

	require.False(t, pal.enableJSON)

	pal.SetEnableJSON(true)
	require.True(t, pal.enableJSON)

	pal.SetEnableJSON(false)
	require.False(t, pal.enableJSON)
}

func TestPolicyAuditLoggerThreadSafety(t *testing.T) {
	logger := logrus.New()
	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel, false)

	// Run concurrent operations to verify thread safety
	done := make(chan bool, 10)

	for i := 0; i < 10; i++ {
		go func(id int) {
			pal.LogDecision(uint32(id), "test-policy", "allow", "test")
			done <- true
		}(i)
	}

	for i := 0; i < 10; i++ {
		<-done
	}

	// If we get here without deadlock or panic, thread safety test passes
	require.True(t, true)
}

func TestPolicyAuditLoggerNilLogger(t *testing.T) {
	pal := NewPolicyAuditLogger(nil, logrus.InfoLevel, false)
	require.NotNil(t, pal)

	// Should handle nil logger gracefully without panic
	pal.LogDecision(100, "test-policy", "allow", "test")
	pal.SetLogLevel(logrus.DebugLevel)
	pal.SetEnableJSON(true)
}

func TestPolicyAuditLoggerLogDecisionWithLogfields(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	logger.SetOutput(buffer)
	logger.SetFormatter(&logrus.JSONFormatter{})

	pal := NewPolicyAuditLogger(logger, logrus.InfoLevel, false)

	// Log a decision with an identity from logfields
	pal.LogDecision(uint32(identity.ReservedIdentityWorld), "world-policy", "allow", "world identity")

	output := buffer.String()
	require.NotEmpty(t, output)

	var logEntry map[string]interface{}
	err := json.Unmarshal(buffer.Bytes(), &logEntry)
	require.NoError(t, err)

	// Verify the identity field is present in the log
	identity, ok := logEntry[logfields.Identity]
	require.True(t, ok)
	require.NotNil(t, identity)
}

func TestAuditDecisionJSON(t *testing.T) {
	decision := AuditDecision{
		Identity:  100,
		Policy:    "test-policy",
		Verdict:   "allow",
		Reason:    "matched",
		Timestamp: 1234567890,
	}

	data, err := json.Marshal(decision)
	require.NoError(t, err)

	var unmarshaled AuditDecision
	err = json.Unmarshal(data, &unmarshaled)
	require.NoError(t, err)
	require.Equal(t, decision, unmarshaled)
}

func TestAuditEvaluationJSON(t *testing.T) {
	evaluation := AuditEvaluation{
		PolicyKey:      "policy:100",
		Result:         "matched",
		IdentitiesHit:  5,
		IdentitiesMiss: 2,
		Timestamp:      1234567890,
	}

	data, err := json.Marshal(evaluation)
	require.NoError(t, err)

	var unmarshaled AuditEvaluation
	err = json.Unmarshal(data, &unmarshaled)
	require.NoError(t, err)
	require.Equal(t, evaluation, unmarshaled)
}

